contracts/DocumentVerification.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";

/**
 * @title DocumentVerification
 * @dev Handles multi-role verification of trade documents using a semaphore-style approval model.
 */
contract DocumentVerification {
    TradeRegistry public tradeRegistry;

    struct VerificationState {
        string docIpfsHash;
        bool customsVerified;
        bool bankVerified;
        bool isFullyVerified;
    }

    mapping(uint256 => VerificationState) public verifications;

    event DocumentsSubmitted(uint256 indexed tradeId, string ipfsHash);
    event VerificationUpdated(uint256 indexed tradeId, string role, bool status);
    event DocumentsFullyVerified(uint256 indexed tradeId);

    address public customs;

    modifier onlyCustoms() {
        require(msg.sender == customs, "Only customs");
        _;
    }

    constructor(address _tradeRegistry, address _customs) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
        customs = _customs;
    }

    function submitDocuments(uint256 _tradeId, string calldata _ipfsHash) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.exporter, "Only exporter can submit docs");
        require(trade.status == TradeRegistry.TradeStatus.LOC_ISSUED, "LoC not issued");

        verifications[_tradeId].docIpfsHash = _ipfsHash;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.DOCS_SUBMITTED);

        emit DocumentsSubmitted(_tradeId, _ipfsHash);
    }

    function verifyAsCustoms(uint256 _tradeId) external onlyCustoms {
        verifications[_tradeId].customsVerified = true;
        emit VerificationUpdated(_tradeId, "Customs", true);
        _checkFullVerification(_tradeId);
    }

    function verifyAsBank(uint256 _tradeId) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.advisingBank || msg.sender == trade.issuingBank, "Only banks can verify");
        require(trade.status == TradeRegistry.TradeStatus.DOCS_SUBMITTED, "Docs not submitted");

        verifications[_tradeId].bankVerified = true;
        emit VerificationUpdated(_tradeId, "Bank", true);
        _checkFullVerification(_tradeId);
    }

    function _checkFullVerification(uint256 _tradeId) internal {
        VerificationState storage state = verifications[_tradeId];
        if (state.customsVerified && state.bankVerified && !state.isFullyVerified) {
            state.isFullyVerified = true;
            tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.DOCS_VERIFIED);
            emit DocumentsFullyVerified(_tradeId);
        }
    }
}

contracts/LetterOfCredit.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";

/**
 * @title LetterOfCredit
 * @dev Handles the LoC lifecycle, funds locking, and bank approvals.
 */
contract LetterOfCredit {
    TradeRegistry public tradeRegistry;

    struct LoC {
        uint256 tradeId;
        uint256 amount;
        uint256 expiry;
        bool isIssued;
        bool fundsLocked;
    }

    mapping(uint256 => LoC) public locs;

    event LoCRequested(uint256 indexed tradeId, uint256 amount);
    event LoCIssued(uint256 indexed tradeId);
    event FundsLocked(uint256 indexed tradeId, uint256 amount);

    constructor(address _tradeRegistry) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
    }

    modifier onlyIssuingBank(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.issuingBank, "Only issuing bank");
        _;
    }

    modifier onlyImporter(uint256 _tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.importer, "Only importer");
        _;
    }

    function requestLoC(uint256 _tradeId, uint256 _expiry) external onlyImporter(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.CREATED, "Invalid trade status");

        locs[_tradeId] = LoC({
            tradeId: _tradeId,
            amount: trade.amount,
            expiry: _expiry,
            isIssued: false,
            fundsLocked: false
        });

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.LOC_REQUESTED);
        emit LoCRequested(_tradeId, trade.amount);
    }

    function issueLoC(uint256 _tradeId) external onlyIssuingBank(_tradeId) {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(trade.status == TradeRegistry.TradeStatus.LOC_REQUESTED, "LoC not requested");

        LoC storage loc = locs[_tradeId];
        require(!loc.isIssued, "Already issued");

        loc.isIssued = true;
        loc.fundsLocked = true;

        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.LOC_ISSUED);
        emit LoCIssued(_tradeId);
        emit FundsLocked(_tradeId, loc.amount);
    }
}

contracts/PaymentSettlement.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./TradeRegistry.sol";
import "./DocumentVerification.sol";

/**
 * @title PaymentSettlement
 * @dev Handles escrow authorization based on verification and delivery signals.
 */
contract PaymentSettlement {
    TradeRegistry public tradeRegistry;
    DocumentVerification public docVerification;

    mapping(uint256 => bool) public importerConfirmedReceipt;

    event PaymentAuthorized(uint256 indexed tradeId, uint256 amount);
    event ReceiptConfirmed(uint256 indexed tradeId);

    constructor(address _tradeRegistry, address _docVerification) {
        tradeRegistry = TradeRegistry(_tradeRegistry);
        docVerification = DocumentVerification(_docVerification);
    }

    function confirmReceipt(uint256 _tradeId) external {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        require(msg.sender == trade.importer, "Only importer can confirm receipt");
        require(trade.status == TradeRegistry.TradeStatus.DOCS_VERIFIED, "Documents not yet verified");

        importerConfirmedReceipt[_tradeId] = true;
        tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.GOODS_RECEIVED);

        emit ReceiptConfirmed(_tradeId);
        _authorizePayment(_tradeId);
    }

    function _authorizePayment(uint256 _tradeId) internal {
        TradeRegistry.Trade memory trade = tradeRegistry.getTrade(_tradeId);
        (, , , bool isFullyVerified) = docVerification.verifications(_tradeId);

        if (isFullyVerified && importerConfirmedReceipt[_tradeId]) {
            tradeRegistry.updateStatus(_tradeId, TradeRegistry.TradeStatus.PAYMENT_AUTHORIZED);
            emit PaymentAuthorized(_tradeId, trade.amount);
        }
    }
}

contracts/TradeRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title TradeRegistry
 * @dev Manages the overall trade state and participants.
 */
contract TradeRegistry {
    enum TradeStatus {
        CREATED,
        LOC_REQUESTED,
        LOC_ISSUED,
        DOCS_SUBMITTED,
        DOCS_VERIFIED,
        GOODS_RECEIVED,
        PAYMENT_AUTHORIZED,
        COMPLETED,
        DISPUTED,
        EXPIRED
    }

    struct Trade {
        uint256 tradeId;
        address importer;
        address exporter;
        address issuingBank;
        address advisingBank;
        TradeStatus status;
        uint256 createdAt;
        uint256 amount;
    }

    mapping(uint256 => Trade) public trades;
    mapping(address => bool) public authorizedContracts;
    address public owner;
    uint256 public nextTradeId;

    event TradeCreated(uint256 indexed tradeId, address importer, address exporter, uint256 amount);
    event TradeStatusUpdated(uint256 indexed tradeId, TradeStatus newStatus);
    event ContractAuthorized(address indexed contractAddress, bool authorized);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyAuthorized() {
        require(authorizedContracts[msg.sender] || msg.sender == owner, "Not authorized");
        _;
    }

    modifier onlyParticipant(uint256 _tradeId) {
        Trade storage trade = trades[_tradeId];
        require(
            msg.sender == trade.importer ||
            msg.sender == trade.exporter ||
            msg.sender == trade.issuingBank ||
            msg.sender == trade.advisingBank,
            "Not a participant"
        );
        _;
    }

    function createTrade(
        address _exporter,
        address _issuingBank,
        address _advisingBank,
        uint256 _amount
    ) external returns (uint256) {
        uint256 tradeId = nextTradeId++;
        trades[tradeId] = Trade({
            tradeId: tradeId,
            importer: msg.sender,
            exporter: _exporter,
            issuingBank: _issuingBank,
            advisingBank: _advisingBank,
            status: TradeStatus.CREATED,
            createdAt: block.timestamp,
            amount: _amount
        });

        emit TradeCreated(tradeId, msg.sender, _exporter, _amount);
        return tradeId;
    }

    function setAuthorizedContract(address _contract, bool _authorized) external onlyOwner {
        authorizedContracts[_contract] = _authorized;
        emit ContractAuthorized(_contract, _authorized);
    }

    function updateStatus(uint256 _tradeId, TradeStatus _newStatus) external onlyAuthorized {
        trades[_tradeId].status = _newStatus;
        emit TradeStatusUpdated(_tradeId, _newStatus);
    }

    function getTrade(uint256 _tradeId) external view returns (Trade memory) {
        return trades[_tradeId];
    }
}

